import base64
import requests
import xml.etree.ElementTree as ET
from urllib.parse import quote

class SAMLServiceProvider:
    def __init__(self, destination_url, user_info):
        self.destination_url = destination_url
        self.user_info = user_info

    def build_saml_request(self):
        root = ET.Element("samlp:AuthnRequest", {
            "xmlns:samlp": "urn:oasis:names:tc:SAML:2.0:protocol",
            "xmlns:saml": "urn:oasis:names:tc:SAML:2.0:assertion",
            "ID": self.generate_id(),
            "Version": "2.0",
            "IssueInstant": self.get_current_time(),
            "Destination": self.destination_url,
            "AssertionConsumerServiceURL": "https://yourapp.com/acs"
        })

        issuer = ET.SubElement(root, "saml:Issuer")
        issuer.text = "https://yourapp.com/sp"

        name_id_policy = ET.SubElement(root, "samlp:NameIDPolicy", {
            "Format": "urn:oasis:names:tc:SAML:1.1:nameid-format:unspecified",
            "AllowCreate": "true"
        })

        # Add user information as attributes
        for key, value in self.user_info.items():
            attribute = ET.SubElement(root, "saml:Attribute", {
                "Name": key,
                "Format": "urn:oasis:names:tc:SAML:1.1:nameid-format:unspecified"
            })
            attribute.text = self.escape_xml(value)

        return ET.tostring(root, encoding='utf-8', xml_declaration=True)

    def escape_xml(self, value):
        return str(value).replace("&", "&amp;").replace("<", "&lt;").replace(">", "&gt;")

    def generate_id(self):
        import uuid
        return f"_{uuid.uuid4()}"

    def get_current_time(self):
        from datetime import datetime
        return datetime.utcnow().isoformat() + "Z"

    def send_saml_request(self):
        saml_request = self.build_saml_request()
        encoded_request = base64.b64encode(saml_request).decode('utf-8')
        post_data = {
            'SAMLRequest': quote(encoded_request)
        }
        response = requests.post(self.destination_url, data=post_data)
        return response

